	@SuppressWarnings("unchecked")
	private static Map<String, WorkbenchServlet> servlets(WorkbenchGateway gateway) {
		try {
			java.lang.reflect.Field field = WorkbenchGateway.class.getDeclaredField("servlets");
			field.setAccessible(true);
			return (Map<String, WorkbenchServlet>) field.get(gateway);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError("Could not read servlet cache", e);
		}
	}

	private static final class TestWorkbenchGateway extends WorkbenchGateway {
		private final CookieHandler cookieHandler;
		private final ServerValidator serverValidator;
		private final List<RecordingWorkbenchServlet> createdServlets = new ArrayList<>();
		private Map<String, String> lastServletConfigParams = Map.of();
		private CountDownLatch blockFirstServletInit;
		private CountDownLatch allowFirstServletInit;

		private TestWorkbenchGateway(CookieHandler cookieHandler, ServerValidator serverValidator) {
			this.cookieHandler = cookieHandler;
			this.serverValidator = serverValidator;
		}

		private TestWorkbenchGateway initAndReturn(ServletConfig config) throws ServletException {
			init(config);
			return this;
		}

		@Override
		protected CookieHandler createCookieHandler(ServletConfig config) {
			return cookieHandler;
		}

		@Override
		protected ServerValidator createServerValidator(ServletConfig config) {
			return serverValidator;
		}

		@Override
		protected WorkbenchServlet createWorkbenchServlet() {
			RecordingWorkbenchServlet servlet = new RecordingWorkbenchServlet(blockFirstServletInit,
					allowFirstServletInit);
			createdServlets.add(servlet);
			return servlet;
		}

		@Override
		protected ServletConfig createWorkbenchServletConfig(String server, Map<String, String> params) {
			lastServletConfigParams = new LinkedHashMap<>(params);
			return TestServletConfig.withParams(server, flatten(params));
		}

		private String[] flatten(Map<String, String> params) {
			String[] flattened = new String[params.size() * 2];
			int i = 0;
			for (Map.Entry<String, String> entry : params.entrySet()) {
				flattened[i++] = entry.getKey();
				flattened[i++] = entry.getValue();
			}
			return flattened;
		}
	}

	private static final class RecordingWorkbenchServlet extends WorkbenchServlet {
		private int serviceCount;
		private int resetCount;
		private int destroyCount;
		private final CountDownLatch enteredInit;
		private final CountDownLatch releaseInit;

		private RecordingWorkbenchServlet(CountDownLatch enteredInit, CountDownLatch releaseInit) {
			this.enteredInit = enteredInit;
			this.releaseInit = releaseInit;
		}

		@Override
		public void init(ServletConfig config) {
			if (enteredInit != null) {
				enteredInit.countDown();
			}
			if (releaseInit != null) {
				try {
					releaseInit.await(5, TimeUnit.SECONDS);
				} catch (InterruptedException e) {
					throw new RuntimeException(e);
				}
			}
			this.config = config;
		}

		@Override
		public void service(HttpServletRequest req, HttpServletResponse resp) {
			serviceCount++;
		}

		@Override
		public void resetCache() {
			resetCount++;
		}

		@Override
		public void destroy() {
			destroyCount++;
		}
	}

	private static final class TestCookieHandler extends CookieHandler {
		private final Map<String, String> cookies = new LinkedHashMap<>();
		private final Map<String, String> addedCookies = new LinkedHashMap<>();

		private TestCookieHandler(String maxAge) {
			super(maxAge);
		}

		@Override
		protected String getCookie(HttpServletRequest req, HttpServletResponse resp, String name) {
			return cookies.get(name);
		}

		@Override
		protected void addNewCookie(HttpServletRequest req, HttpServletResponse resp, String name, String value) {
			addedCookies.put(name, value);
		}
	}

	private static final class FailingServletOutputStream extends ServletOutputStream {
		@Override
		public void write(int b) throws java.io.IOException {
			throw new java.io.IOException("stream boom");
		}

		@Override
		public boolean isReady() {
			return true;
		}

		@Override
		public void setWriteListener(WriteListener writeListener) {
			// not needed for unit tests
		}
	}
